import sys, json
for line in sys.stdin:
    try:
        d = json.loads(line.strip())
        role = d.get('role','?')
        content = d.get('content','')
        if isinstance(content, list):
            for c in content:
                if c.get('type') == 'text':
                    print(f'[{role}] {c[\"text\"][:200]}')
        elif isinstance(content, str):
            print(f'[{role}] {content[:200]}')
    except:
        pass
" 2>/dev/null | tail -20

